#include <stdio.h>
#include <stdlib.h>

int cmp(const void *a, const void *b){
    return (*(int*)a) - (*(int*)b);
}

void dfs(int idx, int n, int target, int *a, int curSum, int *cur, int curLen, int ***res, int *resSize, int *resCap){
    if(curSum == target){
        if(*resSize == *resCap){
            *resCap *= 2;
            *res = realloc(*res, (*resCap) * sizeof(int*));
        }
        int *subset = malloc((curLen+1) * sizeof(int)); // first element stores length
        subset[0] = curLen;
        for(int i=0;i<curLen;i++) subset[i+1] = cur[i];
        (*res)[*resSize] = subset;
        (*resSize)++;
        return;
    }
    if(idx == n || curSum > target) return;
    // skip
    dfs(idx+1, n, target, a, curSum, cur, curLen, res, resSize, resCap);
    // take
    cur[curLen] = a[idx];
    dfs(idx+1, n, target, a, curSum + a[idx], cur, curLen+1, res, resSize, resCap);
}

int subsetCmp(const void *p1, const void *p2){
    int *a = *(int**)p1;
    int *b = *(int**)p2;
    int lenA = a[0];
    int lenB = b[0];
    int minLen = lenA < lenB ? lenA : lenB;
    for(int i=1;i<=minLen;i++){
        if(a[i] != b[i]) return a[i] - b[i];
    }
    return lenA - lenB;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, X; scanf("%d %d", &N, &X);
        int *a = malloc(N * sizeof(int));
        for(int i=0;i<N;i++) scanf("%d", &a[i]);
        qsort(a, N, sizeof(int), cmp);
        int *cur = malloc(N * sizeof(int));
        int **res = malloc(16 * sizeof(int*));
        int resSize = 0, resCap = 16;
        dfs(0, N, X, a, 0, cur, 0, &res, &resSize, &resCap);
        if(resSize){
            qsort(res, resSize, sizeof(int*), subsetCmp);
            for(int i=0;i<resSize;i++){
                int len = res[i][0];
                for(int j=1;j<=len;j++) printf("%d ", res[i][j]);
                printf("\n");
                free(res[i]);
            }
        }
        free(res);
        free(a);
        free(cur);
    }
    return 0;
}

