#include <bits/stdc++.h>
using namespace std;

void backtrack(int idx, const vector<int>& a, int target, vector<int>& cur, vector<vector<int>>& ans){
    if(target==0){
        ans.push_back(cur);
        return;
    }
    if(idx==(int)a.size() || target<0) return;
    // skip current element
    backtrack(idx+1, a, target, cur, ans);
    // take current element
    cur.push_back(a[idx]);
    backtrack(idx+1, a, target - a[idx], cur, ans);
    cur.pop_back();
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N, X; cin>>N>>X;
        vector<int> a(N);
        for(int &v: a) cin>>v;
        sort(a.begin(), a.end());
        vector<vector<int>> ans;
        vector<int> cur;
        backtrack(0, a, X, cur, ans);
        sort(ans.begin(), ans.end());
        for(const auto& vec: ans){
            for(int v: vec) cout<<v<<' ';
            cout<<"\n";
        }
    }
    return 0;
}

