import java.io.*;
import java.util.*;

public class Main {
    static void dfs(int idx, int[] a, int target, List<Integer> cur, List<List<Integer>> ans){
        if(target==0){
            ans.add(new ArrayList<>(cur));
            return;
        }
        if(idx==a.length || target<0) return;
        // skip
        dfs(idx+1, a, target, cur, ans);
        // take
        cur.add(a[idx]);
        dfs(idx+1, a, target - a[idx], cur, ans);
        cur.remove(cur.size()-1);
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while(T-- > 0){
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int X = Integer.parseInt(st.nextToken());
            int[] a = new int[N];
            st = new StringTokenizer(br.readLine());
            for(int i=0;i<N;i++) a[i] = Integer.parseInt(st.nextToken());
            Arrays.sort(a);
            List<List<Integer>> ans = new ArrayList<>();
            dfs(0, a, X, new ArrayList<>(), ans);
            ans.sort(Comparator.comparing(Object::toString)); // lexicographic
            for(List<Integer> list : ans){
                for(int v : list) out.append(v).append(' ');
                out.append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

code.JavaScript:
const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let pos = 0;
const T = input[pos++];
let output = [];
function dfs(idx, a, target, cur, res){
    if(target===0){
        res.push(cur.slice());
        return;
    }
    if(idx===a.length || target<0) return;
    dfs(idx+1, a, target, cur, res); // skip
    cur.push(a[idx]);
    dfs(idx+1, a, target - a[idx], cur, res); // take
    cur.pop();
}
for(let t=0; t<T; t++){
    const N = input[pos++];
    const X = input[pos++];
    const a = input.slice(pos, pos+N); pos+=N;
    a.sort((x,y)=>x-y);
    const subsets = [];
    dfs(0, a, X, [], subsets);
    subsets.sort((p,q)=>{
        const len = Math.min(p.length, q.length);
        for(let i=0;i<len;i++) if(p[i]!==q[i]) return p[i]-q[i];
        return p.length - q.length;
    });
    for(const s of subsets){
        output.push(s.join(' '));
    }
}
console.log(output.join('\n'));

